const html = $('Forbered email').first().json.html;
const subject = $('Forbered email').first().json.subject;

const godkendUrl = `${webhookUrl}?godkend=ja`;
const afvisUrl = `${webhookUrl}?godkend=nej`;

const previewHtml = `
<h2>Godkend nyhedsbrev før afsendelse</h2>
<p>${subject}</p>
<hr>
${html}
<hr>
<p>
  <a href="${godkendUrl}" style="background:#28a745;color:white;padding:10px 20px;text-decoration:none;margin-right:10px">
    ✅ GODKEND
  </a>
  <a href="${afvisUrl}" style="background:#dc3545;color:white;padding:10px 20px;text-decoration:none">
    ❌ AFVIS
  </a>
</p>
`;

return {
  json: {
    previewHtml: previewHtml,
    subject: subject,
    html: html
  }
};

let raw = $json.output;

// Fjern escaped linjeskift og parse JSON
raw = String(raw).replace(/\\n/g, '\n').trim();

// Fjern markdown code blocks
raw = raw
  .replace(/```json\n/g, '')
  .replace(/```\n/g, '')
  .replace(/```/g, '')
  .trim();

const parsed = JSON.parse(raw);

// Beregn total hvis den mangler
const total = parsed.total || 
  parsed.faktuel_præcision.score + 
  parsed.tone.score + 
  parsed.format.score;

return {
  json: {
    faktuel_præcision: parsed.faktuel_præcision,
    tone: parsed.tone,
    format: parsed.format,
    total: total
  }
};

